#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[1000005];
        scanf("%s", s);
        int n = strlen(s);
        char a = s[0];
        char b = s[n-1];
        int cur = 0, best = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == a || s[i] == b) {
                if (cur > best) best = cur;
                cur = 0;
            } else {
                ++cur;
            }
        }
        if (cur > best) best = cur;
        if (best == 0) printf("-1\n");
        else printf("%d\n", best);
    }
    return 0;
}

