#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        s = data[idx]; idx += 1
        a = s[0]
        b = s[-1]
        cur = best = 0
        for ch in s:
            if ch == a or ch == b:
                if cur > best:
                    best = cur
                cur = 0
            else:
                cur += 1
        if cur > best:
            best = cur
        out_lines.append(str(best if best else -1))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

